/*
  Design System
  Based on provided palette, typography and Apiary-like layout
*/

:root {
  /* Colors */
  --color-primary-1: #3F4654; /* header background */
  --color-primary-2: #007ACC; /* links, accents */

  --color-secondary-1: #3CB878;
  --color-secondary-2: #7F8C8D;

  --color-neutral-0: #FFFFFF;
  --color-neutral-1: #F7F7F7;
  --color-neutral-2: #E5E5E5;
  --color-neutral-3: #333333;
  --color-neutral-4: #999999;

  --color-success: #3CB878;
  --color-error: #E74C3C;
  --color-warning: #F1C40F;
  --color-info: #007ACC;

  /* Typography */
  --font-heading: 'Space Grotesk', Helvetica, sans-serif;
  --font-body: 'Source Sans 3', Arial, sans-serif;
  --font-code: 'Source Code Pro', Menlo, monospace;

  --font-size-h1: 28px;
  --font-size-h2: 22px;
  --font-size-h3: 18px;
  --font-size-body: 14px;
  --font-size-small: 12px;

  --font-weight-light: 300;
  --font-weight-regular: 400;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.75;

  /* Spacing scale (8px base) */
  --space-0-5: 4px;
  --space-1: 8px;
  --space-2: 16px;
  --space-3: 24px;
  --space-4: 32px;
  --space-5: 48px;
  --space-6: 64px;

  /* Layout */
  --header-height: 64px;
  --sidebar-width: 220px;
  --content-max-width: 860px;
  --border-radius-small: 2px;
  --border-radius-medium: 4px;
}

/* Reset & base styles */

*, *::before, *::after {
  box-sizing: border-box;
}

html {
  height: 100%;
}

body {
  min-height: 100%;
  margin: 0;
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-normal);
  color: var(--color-neutral-3);
  background-color: var(--color-neutral-0);
}

img {
  max-width: 100%;
  height: auto;
}

a {
  color: var(--color-primary-2);
  text-decoration: none;
}

a:hover,
a:focus {
  text-decoration: underline;
}

ul, ol {
  margin: 0;
  padding: 0;
  list-style: none;
}

h1, h2, h3, h4, h5, h6 {
  margin: 0;
  font-family: var(--font-heading);
  font-weight: var(--font-weight-medium);
  line-height: var(--line-height-tight);
}

h1 {
  font-size: var(--font-size-h1);
}

h2 {
  font-size: var(--font-size-h2);
}

h3 {
  font-size: var(--font-size-h3);
}

p {
  margin: 0;
}

code, pre {
  font-family: var(--font-code);
}

.visually-hidden {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  white-space: nowrap;
  border: 0;
}

/* Header */

.site-header {
  position: sticky;
  top: 0;
  z-index: 100;
  height: var(--header-height);
  background-color: var(--color-primary-1);
  color: var(--color-neutral-0);
}

.header-inner {
  max-width: 1200px;
  height: 100%;
  margin: 0 auto;
  padding: 0 var(--space-4);
  display: flex;
  align-items: center;
}

.brand {
  display: flex;
  align-items: center;
  margin-right: var(--space-4);
}

.brand-mark {
  width: 32px;
  height: 32px;
  border-radius: 4px;
  background: linear-gradient(135deg, #3CB878 0%, #3CB878 33%, #007ACC 33%, #007ACC 66%, #7F8C8D 66%, #7F8C8D 100%);
  margin-right: var(--space-1);
}

.brand-text {
  display: flex;
  flex-direction: column;
}

.brand-title {
  font-family: var(--font-heading);
  font-size: 16px;
  font-weight: var(--font-weight-semibold);
  letter-spacing: 0.01em;
}

.brand-subtitle {
  font-size: 11px;
  color: var(--color-neutral-4);
}

.primary-nav {
  flex: 1 1 auto;
}

.primary-nav-list {
  display: flex;
  align-items: center;
}

.primary-nav-item {
  margin: 0;
}

.primary-nav-link {
  display: inline-flex;
  align-items: center;
  padding: 0 var(--space-2);
  height: var(--header-height);
  font-size: 13px;
  font-weight: var(--font-weight-regular);
  color: rgba(255, 255, 255, 0.7);
  border-left: 1px solid rgba(255, 255, 255, 0.06);
}

.primary-nav-item:first-child .primary-nav-link {
  border-left: none;
}

.primary-nav-link:hover,
.primary-nav-link:focus {
  color: var(--color-neutral-0);
  text-decoration: none;
}

.primary-nav-item.is-active .primary-nav-link {
  color: var(--color-neutral-0);
  font-weight: var(--font-weight-semibold);
}

.header-meta {
  display: flex;
  align-items: center;
  margin-left: var(--space-3);
}

.meta-label {
  font-size: 12px;
  color: rgba(255, 255, 255, 0.8);
}

/* Optional user menu (hidden avatar by default; visible if needed) */

.user-menu {
  position: relative;
  margin-left: var(--space-2);
}

.user-avatar {
  width: 28px;
  height: 28px;
  border-radius: 50%;
  border: 0;
  padding: 0;
  margin: 0;
  background: radial-gradient(circle at 30% 30%, #FFFFFF 0, #FFFFFF 15%, #7F8C8D 16%, #3F4654 100%);
  cursor: pointer;
  outline: none;
}

.user-avatar:focus-visible {
  box-shadow: 0 0 0 2px var(--color-primary-2);
}

.user-dropdown {
  position: absolute;
  right: 0;
  top: calc(100% + var(--space-1));
  min-width: 180px;
  padding: var(--space-1) 0;
  background-color: var(--color-neutral-0);
  border-radius: var(--border-radius-medium);
  border: 1px solid var(--color-neutral-2);
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.08);
  display: none;
  z-index: 10;
}

.user-dropdown a {
  display: block;
  padding: var(--space-1) var(--space-2);
  font-size: var(--font-size-small);
  color: var(--color-neutral-3);
}

.user-dropdown a:hover,
.user-dropdown a:focus {
  background-color: var(--color-neutral-1);
  text-decoration: none;
}

.user-menu:hover .user-dropdown {
  display: block;
}

/* Layout */

.layout {
  display: flex;
  max-width: 1200px;
  margin: 0 auto;
}

.sidebar {
  width: var(--sidebar-width);
  border-right: 1px solid var(--color-neutral-2);
  background-color: var(--color-neutral-0);
}

.sidebar-inner {
  padding: var(--space-3) var(--space-3) var(--space-3) var(--space-4);
}

.sidebar-title {
  font-size: 13px;
  font-weight: var(--font-weight-semibold);
  text-transform: none;
  color: var(--color-neutral-3);
  margin-bottom: var(--space-2);
}

.sidebar-list {
  list-style: none;
}

.sidebar-item {
  margin-bottom: var(--space-1);
}

.sidebar-link {
  display: inline-block;
  font-size: 13px;
  color: var(--color-primary-2);
}

.sidebar-item.is-active .sidebar-link {
  font-weight: var(--font-weight-semibold);
  color: var(--color-primary-2);
}

.content {
  flex: 1 1 auto;
  max-width: var(--content-max-width);
  padding: var(--space-3) var(--space-5);
}

/* Documentation content helpers (for reuse on pages) */

.doc-section {
  margin-bottom: var(--space-4);
}

.doc-section + .doc-section {
  margin-top: var(--space-3);
}

.doc-section-title {
  margin-bottom: var(--space-1);
}

.doc-paragraph {
  margin-top: var(--space-1);
  color: var(--color-neutral-3);
}

.doc-muted {
  color: var(--color-neutral-4);
}

/* Endpoint card pattern */

.endpoint-list {
  margin-top: var(--space-2);
}

.endpoint-card {
  display: flex;
  align-items: center;
  background-color: var(--color-neutral-1);
  border-radius: var(--border-radius-small);
  margin-bottom: var(--space-1);
  padding: var(--space-1) var(--space-3);
  position: relative;
}

.endpoint-card::before {
  content: '';
  position: absolute;
  left: 0;
  top: 0;
  bottom: 0;
  width: 3px;
  background-color: var(--color-primary-2);
}

.endpoint-card.status-success::before {
  background-color: var(--color-success);
}

.endpoint-card.status-error::before {
  background-color: var(--color-error);
}

.endpoint-card-label {
  font-size: 13px;
  color: var(--color-neutral-3);
}

.endpoint-card-chevron {
  margin-left: auto;
  font-size: 18px;
  color: var(--color-neutral-4);
}

/* Forms (generic) */

.form-group {
  margin-bottom: var(--space-2);
}

.form-label {
  display: block;
  font-size: 12px;
  color: var(--color-neutral-4);
  margin-bottom: var(--space-0-5);
}

.form-control {
  width: 100%;
  padding: 6px 8px;
  border-radius: var(--border-radius-small);
  border: 1px solid var(--color-neutral-2);
  font-family: var(--font-body);
  font-size: var(--font-size-body);
}

.form-control:focus {
  outline: none;
  border-color: var(--color-primary-2);
  box-shadow: 0 0 0 1px rgba(0, 122, 204, 0.15);
}

.form-hint {
  font-size: var(--font-size-small);
  color: var(--color-neutral-4);
  margin-top: var(--space-0-5);
}

.form-error {
  font-size: var(--font-size-small);
  color: var(--color-error);
  margin-top: var(--space-0-5);
}

/* Footer */

.site-footer {
  border-top: 1px solid var(--color-neutral-2);
  background-color: var(--color-neutral-1);
  margin-top: var(--space-5);
}

.footer-inner {
  max-width: 1200px;
  margin: 0 auto;
  padding: var(--space-2) var(--space-4);
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.footer-nav-list {
  display: flex;
  flex-wrap: wrap;
  gap: var(--space-2);
}

.footer-nav-link {
  font-size: var(--font-size-small);
  color: var(--color-neutral-4);
}

.footer-nav-link:hover,
.footer-nav-link:focus {
  color: var(--color-primary-2);
  text-decoration: none;
}

.footer-meta {
  font-size: var(--font-size-small);
  color: var(--color-neutral-4);
}

/* Responsive adjustments */

@media (max-width: 960px) {
  .header-inner {
    padding: 0 var(--space-2);
  }

  .primary-nav-list {
    overflow-x: auto;
  }

  .layout {
    flex-direction: column;
  }

  .sidebar {
    width: 100%;
    border-right: none;
    border-bottom: 1px solid var(--color-neutral-2);
  }

  .sidebar-inner {
    padding: var(--space-2) var(--space-3);
  }

  .content {
    padding: var(--space-3);
  }

  .footer-inner {
    flex-direction: column;
    align-items: flex-start;
    gap: var(--space-1);
  }
}

@media (max-width: 640px) {
  .brand-text {
    display: none;
  }

  .meta-label {
    display: none;
  }
}
